public void testUnionWithNullAndRecord() {
  inFunction(
      "/** @param {null|{x: number}} p */" +
      "function f(p) {}" +
      "var out = {};" +
      "f(out);");
  assertEquals("{x: number}", getType("out").toString());
}

public void testUnionWithUndefinedAndRecord() {
  inFunction(
      "/** @param {undefined|{y: string}} p */" +
      "function f(p) {}" +
      "var out = {};" +
      "f(out);");
  assertEquals("{y: string}", getType("out").toString());
}

public void testUnionWithNumberAndMultipleRecords() {
  inFunction(
      "/** @param {number|{a: boolean}|{b: string}} p */" +
      "function f(p) {}" +
      "var out = {};" +
      "f(out);");
  assertEquals("{a: boolean, b: string}", getType("out").toString());
}
